Query.SQL:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY rownum) AS R,"AE.AE_NUMBER","AE.CASE_NUMBER","GA.ADDRESS_LINE1", "GA.ADDRESS_LINE2", "P.PERSON_REQUESTED_NAME" FROM (SELECT /*+ leading(AE CPR P) */ AE.AE_NUMBER AS "AE.AE_NUMBER", AE.CASE_NUMBER AS "AE.CASE_NUMBER", GA.ADDRESS_LINE1 AS "GA.ADDRESS_LINE1", GA.ADDRESS_LINE2 AS "GA.ADDRESS_LINE2", P.PERSON_REQUESTED_NAME AS "P.PERSON_REQUESTED_NAME" FROM GIVEN_ADDRESSES GA, CASE_PARTY_ROLES CPR, PARTIES P, AE_APPLICATIONS AE WHERE CPR.PARTY_ROLE_CODE = AE.PARTY_AGAINST_PARTY_ROLE_CODE AND CPR.CASE_PARTY_NO = AE.PARTY_AGAINST_CASE_PARTY_NO AND CPR.CASE_NUMBER = AE.CASE_NUMBER AND P.PARTY_ID = CPR.PARTY_ID AND GA.ADDRESS_ID IN ( SELECT GA2.ADDRESS_ID FROM GIVEN_ADDRESSES GA2 WHERE ( (GA2.CASE_NUMBER = CPR.CASE_NUMBER AND GA2.PARTY_ROLE_CODE = CPR.PARTY_ROLE_CODE AND GA2.CASE_PARTY_NO = CPR.CASE_PARTY_NO AND GA2.ADDRESS_LINE1 LIKE NVL(UPPER (${param.address1}), GA2.ADDRESS_LINE1 )AND GA2.ADDRESS_LINE2 LIKE NVL(UPPER (${param.address2}), GA2.ADDRESS_LINE2 )AND GA2.VALID_TO IS NULL ) )) AND ( AE.ISSUING_CRT_CODE = ${param.owningCourtCode} AND AE.CASE_NUMBER LIKE NVL(UPPER (${param.caseNumber}), AE.CASE_NUMBER )AND AE.AE_NUMBER LIKE NVL(UPPER (${param.aeNumber}), AE.AE_NUMBER )AND P.PERSON_REQUESTED_NAME LIKE NVL(UPPER (${param.partyName}), P.PERSON_REQUESTED_NAME )AND ( ${param.empName} IS NULL OR ( SELECT P2.PERSON_REQUESTED_NAME FROM PARTIES P2 WHERE P2.PARTY_ID = AE.DEBTORS_EMPLOYERS_PARTY_ID) LIKE UPPER(${param.empName}) ) ) UNION ALL SELECT /*+ leading(AE CPR1 P) */ AE.AE_NUMBER AS "AE.AE_NUMBER", AE.CASE_NUMBER AS "AE.CASE_NUMBER", GA.ADDRESS_LINE1 AS "GA.ADDRESS_LINE1", GA.ADDRESS_LINE2 AS "GA.ADDRESS_LINE2", P.PERSON_REQUESTED_NAME AS "P.PERSON_REQUESTED_NAME" FROM GIVEN_ADDRESSES GA, CASE_PARTY_ROLES CPR, CASE_PARTY_ROLES CPR1, CPR_TO_CPR_RELATIONSHIP CPR2CPR, PARTIES P, AE_APPLICATIONS AE WHERE CPR1.PARTY_ROLE_CODE = AE.PARTY_AGAINST_PARTY_ROLE_CODE AND CPR1.CASE_PARTY_NO = AE.PARTY_AGAINST_CASE_PARTY_NO AND CPR1.CASE_NUMBER = AE.CASE_NUMBER AND CPR2CPR.CPR_A_CASE_NUMBER = CPR1.CASE_NUMBER AND CPR2CPR.CPR_A_PARTY_ROLE_CODE = CPR1.PARTY_ROLE_CODE AND CPR2CPR.CPR_A_CASE_PARTY_NO = CPR1.CASE_PARTY_NO AND CPR2CPR.DELETED_FLAG = 'N' AND CPR.CASE_NUMBER = CPR2CPR.CPR_B_CASE_NUMBER AND CPR.PARTY_ROLE_CODE = CPR2CPR.CPR_B_PARTY_ROLE_CODE AND CPR.CASE_PARTY_NO = CPR2CPR.CPR_B_CASE_PARTY_NO AND P.PARTY_ID = CPR1.PARTY_ID AND GA.ADDRESS_ID IN ( SELECT GA2.ADDRESS_ID FROM GIVEN_ADDRESSES GA2 WHERE ( (GA2.CASE_NUMBER = CPR.CASE_NUMBER AND GA2.PARTY_ROLE_CODE = CPR.PARTY_ROLE_CODE AND GA2.CASE_PARTY_NO = CPR.CASE_PARTY_NO AND (( ${param.address1} IS not NULL and GA2.ADDRESS_LINE1 LIKE UPPER(${param.address1}) ) AND ( ${param.address2} IS not NULL and GA2.ADDRESS_LINE2 LIKE UPPER(${param.address2}) )) AND GA2.VALID_TO IS NULL ) )) AND ( AE.ISSUING_CRT_CODE = ${param.owningCourtCode} AND AE.CASE_NUMBER LIKE NVL(UPPER (${param.caseNumber}), AE.CASE_NUMBER )AND AE.AE_NUMBER LIKE NVL(UPPER (${param.aeNumber}), AE.AE_NUMBER )AND P.PERSON_REQUESTED_NAME LIKE NVL(UPPER (${param.partyName}), P.PERSON_REQUESTED_NAME )AND ( ${param.empName} IS NULL OR ( SELECT P2.PERSON_REQUESTED_NAME FROM PARTIES P2 WHERE P2.PARTY_ID = AE.DEBTORS_EMPLOYERS_PARTY_ID) LIKE UPPER(${param.empName}) ) )
UNION ALL SELECT /*+ leading(AE CPR1 P) */ AE.AE_NUMBER AS "AE.AE_NUMBER", AE.CASE_NUMBER AS "AE.CASE_NUMBER", CP.ADDRESS_LINE1 AS "GA.ADDRESS_LINE1", CP.ADDRESS_LINE2 AS "GA.ADDRESS_LINE2", P.PERSON_REQUESTED_NAME AS "P.PERSON_REQUESTED_NAME" FROM CODED_PARTIES CP, CASE_PARTY_ROLES CPR, CASE_PARTY_ROLES CPR1, CPR_TO_CPR_RELATIONSHIP CPR2CPR, AE_APPLICATIONS AE, PARTIES P WHERE CPR1.PARTY_ROLE_CODE = AE.PARTY_AGAINST_PARTY_ROLE_CODE AND CPR1.CASE_PARTY_NO = AE.PARTY_AGAINST_CASE_PARTY_NO AND CPR1.CASE_NUMBER = AE.CASE_NUMBER AND CPR2CPR.CPR_A_CASE_NUMBER = CPR1.CASE_NUMBER AND CPR2CPR.CPR_A_PARTY_ROLE_CODE = CPR1.PARTY_ROLE_CODE AND CPR2CPR.CPR_A_CASE_PARTY_NO = CPR1.CASE_PARTY_NO AND CPR2CPR.DELETED_FLAG = 'N' AND CPR.CASE_NUMBER = CPR2CPR.CPR_B_CASE_NUMBER AND CPR.PARTY_ROLE_CODE = CPR2CPR.CPR_B_PARTY_ROLE_CODE AND CPR.CASE_PARTY_NO = CPR2CPR.CPR_B_CASE_PARTY_NO AND P.PARTY_ID = CPR1.PARTY_ID AND ( ${param.address1} IS not NULL and CP.ADDRESS_LINE1 LIKE UPPER(${param.address1})) AND ( ${param.address2} IS not NULL and CP.ADDRESS_LINE2 LIKE UPPER(${param.address2})) AND CP.PARTY_ID = CPR.PARTY_ID AND ( AE.ISSUING_CRT_CODE = ${param.owningCourtCode} AND AE.CASE_NUMBER LIKE NVL(UPPER (${param.caseNumber}), AE.CASE_NUMBER )AND AE.AE_NUMBER LIKE NVL(UPPER (${param.aeNumber}), AE.AE_NUMBER )AND P.PERSON_REQUESTED_NAME LIKE NVL(UPPER (${param.partyName}), P.PERSON_REQUESTED_NAME )AND ( ${param.empName} IS NULL OR ( SELECT P2.PERSON_REQUESTED_NAME FROM PARTIES P2 WHERE P2.PARTY_ID = AE.DEBTORS_EMPLOYERS_PARTY_ID) LIKE UPPER(${param.empName}) ) ) UNION ALL SELECT /*+ leading(AE CPR P) */ AE.AE_NUMBER AS "AE.AE_NUMBER", AE.CASE_NUMBER AS "AE.CASE_NUMBER", GA.ADDRESS_LINE1 AS "GA.ADDRESS_LINE1", GA.ADDRESS_LINE2 AS "GA.ADDRESS_LINE2", P.PERSON_REQUESTED_NAME AS "P.PERSON_REQUESTED_NAME" FROM GIVEN_ADDRESSES GA, CASE_PARTY_ROLES CPR, PARTIES P, AE_APPLICATIONS AE WHERE CPR.PARTY_ROLE_CODE = AE.PARTY_AGAINST_PARTY_ROLE_CODE AND CPR.CASE_PARTY_NO = AE.PARTY_AGAINST_CASE_PARTY_NO AND CPR.CASE_NUMBER = AE.CASE_NUMBER AND P.PARTY_ID = CPR.PARTY_ID AND GA.ADDRESS_ID IN ( SELECT GA2.ADDRESS_ID FROM GIVEN_ADDRESSES GA2 WHERE (( GA2.PARTY_ID = AE.DEBTORS_EMPLOYERS_PARTY_ID AND GA2.ADDRESS_TYPE_CODE = 'EMPLOYER' AND (( ${param.address1} IS not NULL and GA2.ADDRESS_LINE1 LIKE UPPER(${param.address1}) ) AND ( ${param.address2} IS not NULL and GA2.ADDRESS_LINE2 LIKE UPPER(${param.address2}) )) AND GA2.VALID_TO IS NULL ) )) AND ( AE.ISSUING_CRT_CODE = ${param.owningCourtCode} AND AE.CASE_NUMBER LIKE NVL(UPPER (${param.caseNumber}), AE.CASE_NUMBER )AND AE.AE_NUMBER LIKE NVL(UPPER (${param.aeNumber}), AE.AE_NUMBER )AND P.PERSON_REQUESTED_NAME LIKE NVL(UPPER (${param.partyName}), P.PERSON_REQUESTED_NAME )AND ( ${param.empName} IS NULL OR ( SELECT P2.PERSON_REQUESTED_NAME FROM PARTIES P2 WHERE P2.PARTY_ID = AE.DEBTORS_EMPLOYERS_PARTY_ID) LIKE UPPER(${param.empName}) ) )
ORDER BY 2,1,5,3,4 ) ) WHERE R<(${param.pageNumber}*${param.pageSize})+1 AND R>(${param.pageNumber}-1)*${param.pageSize}
